38	  remainingCap?: number;
39	}
40	
41	export interface Damage {
42	  itemType: string;
43	  amount: number;
44	}
45	
46	export interface Incident {
47	  damages: Damage[];
48	}
49	
50	export interface ClaimResult {
51	  payout: number;
52	  remainingCap: number;
53	}
54	
55	const INSURANCE_VALUES: Record<string, number> = {
56	  sword: 1000,
57	  amulet: 600,
58	  staff: 800,
59	  potion: 400,
60	  rune: 250,
61	  moonstone: 250,
62	};
63	const DEDUCTIBLE = 100;
64	const CAP_MULTIPLIER = 2;
65	
66	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
67	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
68	
69	function reimbursableAmount(item: Item | undefined, damageAmount: number): number {
70	  const isHighEnchantment = (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
71	  return isHighEnchantment ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE : damageAmount;
72	}
73	
74	export function claim(policy: Policy, incident: Incident): ClaimResult {
75	  const insuranceSum = policy.items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
76	  const availableCap = policy.remainingCap ?? CAP_MULTIPLIER * insuranceSum;
77	  const rawPayout = incident.damages.reduce((sum, damage) => {
78	    const item = policy.items.find((policyItem) => policyItem.type === damage.itemType);
79	    const reimbursable = reimbursableAmount(item, damage.amount);
80	    return sum + Math.max(0, reimbursable - DEDUCTIBLE);
81	  }, 0);
82	  const payout = Math.floor(Math.min(rawPayout, availableCap));
83	  return { payout, remainingCap: availableCap - payout };
84	}
