86	export function quote(customer: Customer, items: Item[]): number {
87	  const percentageSurcharge = (rate: number, applies: (item: Item) => boolean): number =>
88	    items.filter(applies).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
89	
90	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
91	  // A block of exactly COMPONENTS_PER_BLOCK alike components (same type) replaces their summed base with COMPONENT_BLOCK_BASE.
92	  const blockAdjustment = COMPONENT_TYPES.reduce((adjustment, componentType) => {
93	    const count = items.filter((item) => item.type === componentType).length;
94	    const replacement = COMPONENT_BLOCK_BASE - COMPONENTS_PER_BLOCK * BASE_PREMIUMS[componentType];
95	    return count === COMPONENTS_PER_BLOCK ? adjustment + replacement : adjustment;
96	  }, 0);
97	  const curseSurcharge = percentageSurcharge(CURSE_SURCHARGE_RATE, (item) => item.cursed === true);
98	  const highEnchantmentSurcharge = percentageSurcharge(
99	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
100	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
101	  );
102	  const adjustedBase = baseSum + blockAdjustment;
103	  const proportionalDiscount = (rate: number, qualifies: boolean): number => (qualifies ? adjustedBase * rate : 0);
104	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
105	  const loyaltyDiscount = proportionalDiscount(LOYALTY_DISCOUNT_RATE, customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD);
106	  const followUpDiscount = proportionalDiscount(FOLLOW_UP_DISCOUNT_RATE, (customer.previousContracts ?? 0) >= FOLLOW_UP_CONTRACTS_THRESHOLD);
107	  return Math.ceil(adjustedBase + curseSurcharge + highEnchantmentSurcharge + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
108	}
